import React, {useState} from "react";
import './Welcome.css';

function Welcome (props) {
    const [userName, setUserName] = useState('');
    const [passWord, setPassWord] = useState('');
    const [isLoginSuccessful, setIsLoginSuccessful] = useState(false);
    const handleUsernameChange = (e) => {
        const value = e.target.value;
        setUserName(value);
    }
    const Login = () => {
        console.log('Username: ', userName)
        console.log('Password: ', passWord)
        if (userName === 'admin' && passWord === '1234') {
        setIsLoginSuccessful(true);
        console.log("Successful log in!")
        }
        else {
            console.log("Login failed!");
            isLoginSuccessful(false);
        }
}
    const onSubmit = (e) => {e.preventDefault()}
    const handlePasswordChange = (e) => {
        const value = e.target.value;
        setPassWord(value);
    }
    return  (
    <div className = "welcome-page">
        <h1 className = 'title'>Welcome to Productiv!</h1>
        <Credentials isLoginSuccessful = {isLoginSuccessful}></Credentials>
    <form className = 'location-form' onSubmit={onSubmit}>
        <div>
        <label htmlFor="username"> Username </label>
        <input type="text" id="username" name="username" value = {userName} onChange = {handleUsernameChange}></input>
        </div>
        <div>
        <label htmlFor="password"> Password </label>
        <input type="password" id="password" name="password" value = {passWord} onChange = {handlePasswordChange}></input>
        </div>
        <div>
        <button className ='button' type="submit" value= "Log in" onClick={Login}></button>
        </div>
        <div>
        <button className ='button' type="submit" value= "Sign up" onClick={Credentials}></button>
        </div>
    </form>
    </div>
    )
    function Credentials (props) {
        if (props.isLoginSuccessful) {
            return <div>Successful log in!</div>
        }
            return <div>Login failed!</div>

    }
}

export default Welcome;
